# ============================================================
# Security Utilities
# ============================================================
def hash_password(password, salt=None):
    if salt is None:
        salt = secrets.token_hex(16)
    pw_hash = hashlib.pbkdf2_hmac(
        'sha256', password.encode(), salt.encode(), 100000
    )
    return pw_hash.hex(), salt


def verify_password(password, stored_hash, salt):
    pw_hash = hashlib.pbkdf2_hmac(
        'sha256', password.encode(), salt.encode(), 100000
    )
    return hmac.compare_digest(pw_hash.hex(), stored_hash)


def generate_label_hmac(image_id, annotator_id, label):
    message = f"{image_id}:{annotator_id}:{label}".encode()
    return hmac.new(SECRET_KEY.encode(), message, hashlib.sha256).hexdigest()


def verify_label_hmac(image_id, annotator_id, label, signature):
    expected = generate_label_hmac(image_id, annotator_id, label)
    return hmac.compare_digest(expected, signature)


def generate_api_token():
    return secrets.token_urlsafe(48)


