def check_rate_limit(conn, annotator_id):
    window_start = datetime.utcnow().strftime("%Y-%m-%d %H:00:00")
    cursor = conn.cursor()
    cursor.execute(
        "SELECT request_count FROM rate_limits WHERE annotator_id=? AND window_start=?",
        (annotator_id, window_start)
    )
    row = cursor.fetchone()
    if row and row['request_count'] >= MAX_LABELS_PER_ANNOTATOR_PER_HOUR:
        return False
    if row:
        cursor.execute(
            "UPDATE rate_limits SET request_count = request_count + 1 WHERE annotator_id=? AND window_start=?",
            (annotator_id, window_start)
        )
    else:
        cursor.execute(
            "INSERT INTO rate_limits (annotator_id, window_start, request_count) VALUES (?, ?, 1)",
            (annotator_id, window_start)
        )
    conn.commit()
    return True


