# Label Aggregation with Weighted Majority Voting
# ============================================================
def aggregate_labels(conn, image_id):
    cursor = conn.cursor()

    # Get all valid labels for this image with annotator trust scores
    cursor.execute("""
        SELECT l.label, l.annotator_id, a.trust_score
        FROM labels l
        JOIN annotators a ON l.annotator_id = a.id
        WHERE l.image_id = ? AND l.is_valid = 1 AND a.is_active = 1
    """, (image_id,))

    results = cursor.fetchall()

    if len(results) < MIN_ANNOTATORS_FOR_CONSENSUS:
        return None, 0.0

    # Weighted majority voting
    weighted_votes = Counter()
    total_weight = 0.0

    for r in results:
        weight = max(r['trust_score'], 0.1)  # Minimum weight to avoid zero
        weighted_votes[r['label']] += weight
        total_weight += weight

    if total_weight == 0:
        return None, 0.0

    # Get the label with highest weighted vote
    consensus_label, consensus_weight = weighted_votes.most_common(1)[0]
    confidence = consensus_weight / total_weight

    if confidence >= AGREEMENT_THRESHOLD:
        cursor.execute("""
            UPDATE images SET consensus_label=?, consensus_confidence=?, is_finalized=1
            WHERE id=?
        """, (consensus_label, confidence, image_id))
        conn.commit()

        log_audit(conn, "CONSENSUS_REACHED", None, image_id,
                  f"Label: {consensus_label}, Confidence: {confidence:.3f}")

        # Detect potential label flipping: check if any annotator consistently disagrees
        for r in results:
            if r['label'] != consensus_label:
                _check_for_label_flipping(conn, r['annotator_id'])

        return consensus_label, confidence

    return None, confidence


def _check_for_label_flipping(conn, annotator_id):
    """Detect systematic label flipping attacks."""
    cursor = conn.cursor()

    # Get recent disagreements with consensus
    cursor.execute("""
        SELECT COUNT(*) as total,
               SUM(CASE WHEN l.label != i.consensus_label THEN 1 ELSE 0 END) as disagreements
        FROM labels l
        JOIN images i ON l.image_id = i.id
        WHERE l.annotator_id = ? AND i.is_finalized = 1 AND l.is_valid = 1
        AND l.submitted_at > datetime('now', '-24 hours')
    """, (annotator_id,))

    row = cursor.fetchone()
    if row and row['total'] >= 10:
        disagreement_rate = row['disagreements'] / row['total']
        if disagreement_rate > 0.7:
            # High disagreement rate - potential label flipper
            log_audit(conn, "LABEL_FLIP_DETECTED", annotator_id, None,
                      f"Disagreement rate: {disagreement_rate:.3f} over {row['total']} labels")

            # Invalidate recent labels from this annotator
            cursor.execute("""
                UPDATE labels SET is_valid = 0
                WHERE annotator_id = ? AND submitted_at > datetime('now', '-24 hours')
            """, (annotator_id,))

            # Reduce trust score significantly
            cursor.execute(
                "UPDATE annotators SET trust_score = MAX(trust_score * 0.3, 0.0), flagged_count = flagged_count + 1 WHERE id=?",
                (annotator_id,)
            )

            conn.commit()


