# Simple ML Model (Logistic Regression from scratch)
# ============================================================
class SimpleImageClassifier:
    """A simple multi-class logistic regression classifier."""

    def __init__(self, n_features=128, learning_rate=0.01, n_iterations=1000):
        self.n_features = n_features
        self.learning_rate = learning_rate
        self.n_iterations = n_iterations
        self.weights = None
        self.bias = None
        self.classes = None
        self.is_trained = False

    def _softmax(self, z):
        exp_z = np.exp(z - np.max(z, axis=1, keepdims=True))
        return exp_z / np.sum(exp_z, axis=1, keepdims=True)

    def _one_hot(self, y, n_classes):
        one_hot = np.zeros((len(y), n_classes))
        for i, val in enumerate(y):
            one_hot[i, val] = 1
        return one_hot

    def train(self, X, y, sample_weights=None):
        n_samples, n_features = X.shape
        self.classes = sorted(set(y))
        n_classes = len(self.classes)

        class_to_idx = {c: i for i, c in enumerate(self.classes)}
        y_idx = np.array([class_to_idx[label] for label in y])

        self.weights = np.random.randn(n_features, n_classes) * 0.01
        self.bias = np.zeros((1, n_classes))

        y_one_hot = self._one_hot(y_idx, n_classes)

        if sample_weights is None:
            sample_weights = np.ones(n_samples) / n_samples
        else:
            sample_weights = np.array(sample_weights)
            sample_weights = sample_weights / sample_weights.sum()

        for iteration in range(self.n_iterations):
            logits = X @ self.weights + self.bias
            probs = self._softmax(logits)

            # Weighted gradient
            error = (probs - y_one_hot) * sample_weights[:, np.newaxis]

            dw = X.T @ error
            db = np.sum(error, axis=0, keepdims=True)

            self.weights -= self.learning_rate * dw
            self.bias -= self.learning_rate * db

            if iteration % 100 == 0:
                loss = -np.sum(
                    sample_weights[:, np.newaxis] * y_one_hot * np.log(probs + 1e-10)
                )
                print(f"  Iteration {iteration}, Loss: {loss:.4f}")

        self.is_trained = True
        print(f"Training complete. Classes: {self.classes}")

    def predict(self, X):
        if not self.is_trained:
            raise ValueError("Model not trained yet")
        logits = X @ self.weights + self.bias
        probs = self._softmax(logits)
        indices = np.argmax(probs, axis=1)
        return [self.classes[i] for i in indices]

    def predict_proba(self, X):
        if not self.is_trained:
            raise ValueError("Model not trained yet")
        logits = X @ self.weights + self.bias
        return self._softmax(logits)


# Global model instance
model = SimpleImageClassifier()


def simulate_image_features(image_path):
    """Simulate extracting features from an image path (deterministic)."""
    seed = int(hashlib.md5(image_path.encode()).hexdigest()[:8], 16)
    rng = np.random.RandomState(seed)
    return rng.randn(128)


def train_model_on_labeled_data():
    """Train the model on all finalized labeled data."""
    conn = get_db()
    cursor = conn.cursor()

    cursor.execute("""
        SELECT i.image_path, i.consensus_label, i.consensus_confidence
        FROM images i
        WHERE i.is_finalized = 1 AND i.consensus_label IS NOT NULL
    """)

    rows = cursor.fetchall()
    conn.close()

    if len(rows) < 5:
        print(f"Not enough labeled data to train ({len(rows)} samples). Need at least 5.")
        return False

    X = []
    y = []
    weights = []

    for row in rows:
        features = simulate_image_features(row['image_path'])
        X.append(features)
        y.append(row['consensus_label'])
        weights.append(row['consensus_confidence'])

    X = np.array(X)
    y = np.array(y)
    weights = np.array(weights)

    print(f"Training model on {len(X)} samples...")
    model.train(X, y, sample_weights=weights)
    print("Model training complete.")
    return True


# ============================================================
# REST API Handler
# ============================================================
class LabelingAPIHandler(BaseHTTPRequestHandler):

    def _send_json(self, status_code, data):
        self.send_response(status_code)
        self.send_header('Content-Type', 'application/json')
        self.end_headers()
        self.wfile.write(json.dumps(data).encode())

    def _read_body(self):
        content_length = int(self.headers.get('Content-Length', 0))
        if content_length == 0:
            return {}
        body = self.rfile.read(content_length)
        return json.loads(body.decode())

    def _authenticate(self):
        """Authenticate via API token in Authorization header."""
        auth_header = self.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return None

        token = auth_header[7:]
        conn = get_db()
        cursor = conn.cursor()
        cursor.execute(
            "SELECT * FROM annotators WHERE api_token=? AND is_active=1",
            (token,)
        )
        annotator = cursor.fetchone()

        if annotator:
            # Check token expiry
            token_created = datetime.fromisoformat(annotator['token_created_at'])
            if datetime.utcnow() - token_created > timedelta(hours=TOKEN_EXPIRY_HOURS):
                conn.close()
                return None

        conn.close()
        return annotator

    def _get_client_ip(self):
        return self.client_address[0]

    def do_POST(self):
        parsed = urlparse(self.path)
        path = parsed.path

        if path == '/api/register':
            self._handle_register()
        elif path == '/api/login':
            self._handle_login()
        elif path == '/api/labels':
            self._handle_submit_label()
        elif path == '/api/images':
            self._handle_add_image()
        elif path == '/api/train':
            self._handle_train()
        elif path == '/api/predict':
            self._handle_predict()
        else:
            self._send_json(404, {"error": "Not found"})

    def do_GET(self):
        parsed = urlparse(self.path)
        path = parsed.path
        params = parse_qs(parsed.query)

        if path == '/api/images':
            self._handle_get_images(params)
        elif path == '/api/labels/status':
            self._handle_label_status(params)
        elif path == '/api/annotators/stats':
            self._handle_annotator_stats()
        elif path == '/api/audit':
            self._handle_get_audit(params)
        elif path == '/api/health':
            self._send_json(200, {"status": "ok"})
        else:
            self._send_json(404, {"error": "Not found"})

    def _handle_register(self):
        try:
            data = self._read_body()
            username = data.get('username', '').strip()
            password = data.get('password', '')

            if not username or not password:
                self._send_json(400, {"error": "Username and password required"})
                return

            if len(username) < 3 or len(username) > 50:
                self._send_json(400, {"error": "Username must be 3-50 characters"})
                return

            if len(password) < 8:
                self._send_json(400, {"error": "Password must be at least 8 characters"})
                return

            # Only allow alphanumeric usernames
            if not username.isalnum():
                self._send_json(400, {"error": "Username must be alphanumeric"})
                return

            pw_hash, salt = hash_password(password)

            with db_lock:
                conn = get_db()
                try:
                    conn.execute(
                        "INSERT INTO annotators (username, password_hash, salt) VALUES (?, ?, ?)",
                        (username, pw_hash, salt)
                    )
                    conn.commit()
                    log_audit(conn, "ANNOTATOR_REGISTERED", None, None, f"Username: {username}")
                    conn.commit()
                    self._send_json(201, {"message": "Registered successfully"})
                except sqlite3.IntegrityError:
                    self._send_json(409, {"error": "Username already exists"})
                finally:
                    conn.close()
        except (json.JSONDecodeError, Exception) as e:
            self._send_json(400, {"error": f"Invalid request: {str(e)}"})

    def _handle_login(self):
        try:
            data = self._read_body()
            username = data.get('username', '')
            password = data.get('password', '')

            conn = get_db()
            cursor = conn.cursor()
            cursor.execute("SELECT * FROM annotators WHERE username=?", (username,))
            annotator = cursor.fetchone()

            if not annotator or not verify_password(password, annotator['password_hash'], annotator['salt']):
                conn.close()
                self._send_json(401, {"error": "Invalid credentials"})
                return

            if not annotator['is_active']:
                conn.close()
                self._send_json(403, {"error": "Account deactivated"})
                return

            token = generate_api_token()
            now = datetime.utcnow().isoformat()

            with db_lock:
                conn.execute(
                    "UPDATE annotators SET api_token=?, token_created_at=? WHERE id=?",
                    (token, now, annotator['id'])
                )
                log_audit(conn, "LOGIN", annotator['id'], None, f"IP: {self._get_client_ip()}")
                conn.commit()

            conn.close()
            self._send_json(200, {
                "token": token,
                "annotator_id": annotator['id'],
                "trust_score": annotator['trust_score']
            })
        except (json.JSONDecodeError, Exception) as e:
            self._send_json(400, {"error": f"Invalid request: {str(e)}"})

    def _handle_add_image(self):
        annotator = self._authenticate()
        if not annotator:
            self._send_json(401, {"error": "Unauthorized"})
            return

        try:
            data = self._read_body()
            image_path = data.get('image_path', '').strip()
            gold_label = data.get('gold_label')
            is_gold = 1 if gold_label else 0

            if not image_path:
                self._send_json(400, {"error": "image_path required"})
                return

            with db_lock:
                conn = get_db()
                try:
                    conn.execute(
                        "INSERT INTO images (image_path, gold_label, is_gold_standard) VALUES (?, ?, ?)",
                        (image_path, gold_label, is_gold)
                    )
                    image_id = conn.execute("SELECT last_insert_rowid()").fetchone()[0]
                    log_audit(conn, "IMAGE_ADDED", annotator['id'], image_id,
                              f"Gold: {is_gold}")
                    conn.commit()
                    self._send_json(201, {"image_id": image_id, "message": "Image added"})
                except sqlite3.IntegrityError:
                    self._send_json(409, {"error": "Image already exists"})
                finally:
                    conn.close()
        except (json.JSONDecodeError, Exception) as e:
            self._send_json(400, {"error": f"Invalid request: {str(e)}"})

    def _handle_submit_label(self):
        annotator = self._authenticate()
        if not annotator:
            self._send_json(401, {"error": "Unauthorized"})
            return

        try:
            data = self._read_body()
            image_id = data.get('image_id')
            label = data.get('label', '').strip()

            if not image_id or not label:
                self._send_json(400, {"error": "image_id and label required"})
                return

            # Validate label format (prevent injection)
            if not label.replace('_', '').replace('-', '').isalnum():
                self._send_json(400, {"error": "Label must be alphanumeric (with _ or -)"})
                return

            if len(label) > 100:
                self._send_json(400, {"error": "Label too long"})
                return

            with db_lock:
                conn = get_db()
                try:
                    # Rate limiting
                    if not check_rate_limit(conn, annotator['id']):
                        self._send_json(429, {"error": "Rate limit exceeded"})
                        conn.close()
                        return

                    # Check image exists and is not finalized
                    cursor = conn.cursor()
                    cursor.execute("SELECT * FROM images WHERE id=?", (image_id,))
                    image = cursor.fetchone()

                    if not image:
                        self._send_json(404, {"error": "Image not found"})
                        conn.close()
                        return

                    if image['is_finalized']:
                        self._send_json(409, {"error": "Image already finalized"})
                        conn.close()
                        return

                    # Generate HMAC for integrity
                    signature = generate_label_hmac(image_id, annotator['id'], label)

                    # Insert label
                    conn.execute("""
                        INSERT INTO labels (image_id, annotator_id, label, ip_address, hmac_signature)
                        VALUES (?, ?, ?, ?, ?)
                    """, (image_id, annotator['id'], label, self._get_client_ip(), signature))

                    # Update annotator total labels
                    conn.execute(
                        "UPDATE annotators SET total_labels = total_labels + 1 WHERE id=?",
                        (annotator['id'],)
                    )

                    log_audit(conn, "LABEL_SUBMITTED", annotator['id'], image_id,
                              f"Label: {label}")
                    conn.commit()

                    # Check if this is a gold standard image
                    if image['is_gold_standard'] and image['gold_label']:
                        if label != image['gold_label']:
                            log_audit(conn, "GOLD_MISMATCH", annotator['id'], image_id,
                                      f"Expected: {image['gold_label']}, Got: {label}")
                        update_trust_score(conn, annotator['id'])

                    # Try to aggregate
                    consensus_label, confidence = aggregate_labels(conn, image_id)

                    response = {
                        "message": "Label submitted",
                        "signature": signature
                    }

                    if consensus_label:
                        response["consensus_reached"] = True
                        response["consensus_label"] = consensus_label
                        response["confidence"] = round(confidence, 3)
                    else:
                        response["consensus_reached"] = False

                    self._send_json(201, response)

                except sqlite3.IntegrityError:
                    self._send_json(409, {"error": "You already labeled this image"})
                finally:
                    conn.close()

        except (json.JSONDecodeError, Exception) as e:
            self._send_json(400, {"error": f"Invalid request: {str(e)}"})

    def _handle_get_images(self, params):
        annotator = self._authenticate()
        if not annotator:
            self._send_json(401, {"error": "Unauthorized"})
            return

        status = params.get('status', ['unlabeled'])[0]
        limit = min(int(params.get('limit', [20])[0]), 100)

        conn = get_db()
        cursor = conn.cursor()

        if status == 'unlabeled':
            # Get images this annotator hasn't labeled yet
            cursor.execute("""
                SELECT i.id, i.image_path, i.is_finalized,
                       (SELECT COUNT(*) FROM labels l WHERE l.image_id = i.id AND l.is_valid = 1) as label_count
                FROM images i
                WHERE i.is_finalized = 0
                AND i.id NOT IN (SELECT image_id FROM labels WHERE annotator_id = ?)
                ORDER BY label_count ASC
                LIMIT ?
            """, (annotator['id'], limit))
        elif status == 'finalized':
            cursor.execute("""
                SELECT i.id, i.image_path, i.consensus_label, i.consensus_confidence
                FROM images i
                WHERE i.is_finalized = 1
                LIMIT ?
            """, (limit,))
        else:
            cursor.execute("SELECT id, image_path, is_finalized FROM images LIMIT ?", (limit,))

        images = [dict(row) for row in cursor.fetchall()]
        conn.close()
        self._send_json(200, {"images": images})

    def _handle_label_status(self, params):
        annotator = self._authenticate()
        if not annotator:
            self._send_json(401, {"error": "Unauthorized"})
            return

        image_id = params.get('image_id', [None])[0]
        if not image_id:
            self._send_json(400, {"error": "image_id parameter required"})
            return

        conn = get_db()
        cursor = conn.cursor()

        cursor.execute("SELECT * FROM images WHERE id=?", (image_id,))
        image = cursor.fetchone()
        if not image:
            conn.close()
            self._send_json(404, {"error": "Image not found"})
            return

        cursor.execute("""
            SELECT COUNT(*) as total_labels,
                   COUNT(DISTINCT annotator_id) as unique_annotators
            FROM labels
            WHERE image_id = ? AND is_valid = 1
        """, (image_id,))
        stats = cursor.fetchone()

        # Verify integrity of stored labels
        cursor.execute("""
            SELECT l.id, l.image_id, l.annotator_id, l.label, l.hmac_signature
            FROM labels l WHERE l.image_id = ? AND l.is_valid = 1
        """, (image_id,))

        integrity_ok = True
        for label_row in cursor.fetchall():
            if not verify_label_hmac(
                label_row['image_id'], label_row['annotator_id'],
                label_row['label'], label_row['hmac_signature']
            ):
                integrity_ok = False
                log_audit(conn, "INTEGRITY_VIOLATION", label_row['annotator_id'],
                          image_id, f"Label ID: {label_row['id']}")

        conn.commit()
        conn.close()

        self._send_json(200, {
            "image_id": int(image_id),
            "is_finalized": bool(image['is_finalized']),
            "consensus_label": image['consensus_label'],
            "consensus_confidence": image['consensus_confidence'],
            "total_labels": stats['total_labels'],
            "unique_annotators": stats['unique_annotators'],
            "integrity_verified": integrity_ok
        })

    def _handle_annotator_stats(self):
        annotator = self._authenticate()
        if not annotator:
            self._send_json(401, {"error": "Unauthorized"})
            return

        conn = get_db()
        cursor = conn.cursor()
        cursor.execute("""
            SELECT id, username, trust_score, total_labels, flagged_count, is_active, created_at
            FROM annotators WHERE id=?
        """, (annotator['id'],))
        stats = dict(cursor.fetchone())

        # Get agreement rate
        cursor.execute("""
            SELECT COUNT(*) as total,
                   SUM(CASE WHEN l.label = i.consensus_label THEN 1 ELSE 0 END) as agreements
            FROM labels l
            JOIN images i ON l.image_id = i.id
            WHERE l.annotator_id = ? AND i.is_finalized = 1 AND l.is_valid = 1
        """, (annotator['id'],))
        agreement = cursor.fetchone()
        if agreement['total'] > 0:
            stats['agreement_rate'] = round(agreement['agreements'] / agreement['total'], 3)
        else:
            stats['agreement_rate'] = None

        conn.close()
        self._send_json(200, stats)

    def _handle_get_audit(self, params):
        annotator = self._authenticate()
        if not annotator:
            self._send_json(401, {"error": "Unauthorized"})
            return

        limit = min(int(params.get('limit', [50])[0]), 200)
        event_type = params.get('event_type', [None])[0]

        conn = get_db()
        cursor = conn.cursor()

        if event_type:
            cursor.execute(
                "SELECT * FROM audit_log WHERE event_type=? ORDER BY timestamp DESC LIMIT ?",
                (event_type, limit)
            )
        else:
            cursor.execute(
                "SELECT * FROM audit_log ORDER BY timestamp DESC LIMIT ?",
                (limit,)
            )

        logs = [dict(row) for row in cursor.fetchall()]
        conn.close()
        self._send_json(200, {"audit_logs": logs})

    def _handle_train(self):
        annotator = self._authenticate()
        if not annotator:
            self._send_json(401, {"error": "Unauthorized"})
            return

        try:
            success = train_model_on_labeled_data()
            if success:
                self._send_json(200, {"message": "Model trained successfully"})
            else:
                self._send_json(400, {"error": "Not enough labeled data"})
        except Exception as e:
            self._send_json(500, {"error": f"Training failed: {str(e)}"})

    def _handle_predict(self):
        annotator = self._authenticate()
        if not annotator:
            self._send_json(401, {"error": "Unauthorized"})
            return

        if not model.is_trained:
            self._send_json(400, {"error": "Model not trained yet"})
            return

        try:
            data = self._read_body()
            image_path = data.get('image_path', '')

            if not image_path:
                self._send_json(400, {"error": "image_path required"})
                return

            features = simulate_image_features(image_path).reshape(1, -1)
            prediction = model.predict(features)[0]
            probabilities = model.predict_proba(features)[0]

            prob_dict = {
                cls: round(float(prob), 4)
                for cls, prob in zip(model.classes, probabilities)
            }

            self._send_json(200, {
                "image_path": image_path,
                "predicted_label": prediction,
                "probabilities": prob_dict
            })
        except Exception as e:
            self._send_json(500, {"error": f"Prediction failed: {str(e)}"})

    def log_message(self, format, *args):
        """Override to add timestamp."""
        print(f"[{datetime.utcnow().isoformat()}] {self.client_address[0]} - {format % args}")


# ============================================================
# Demo / Seed Data
# ============================================================
def seed_demo_data():
    """Seed the database with demo data for testing."""
    conn = get_db()
    cursor = conn.cursor()

    # Check if already seeded
    cursor.execute("SELECT COUNT(*) FROM annotators")
    if cursor.fetchone()[0] > 0:
        conn.close()
        return

    print("Seeding demo data...")

    # Create demo annotators
    annotators = [
        ("alice", "password123!"),
        ("bob", "password456!"),
        ("charlie", "password789!"),
        ("diana", "passwordabc!"),
        ("eve_malicious", "passwordxyz!"),
    ]

    for username, password in annotators:
        pw_hash, salt = hash_password(password)
        conn.execute(
            "INSERT INTO annotators (username, password_hash, salt, trust_score) VALUES (?, ?, ?, ?)",
            (username, pw_hash, salt, 1.0)
        )

    # Create demo images
    categories = ["cat", "dog", "bird", "car", "tree"]
    for i in range(30):
        category = categories[i % len(categories)]
        image_path = f"/images/{category}_{i:04d}.jpg"
        is_gold = 1 if i < 5 else 0
        gold_label = category if is_gold else None
        conn.execute(
            "INSERT INTO images (image_path, gold_label, is_gold_standard) VALUES (?, ?, ?)",
            (image_path, gold_label, is_gold)
        )

    conn.commit()

    # Simulate labeling
    import random
    random.seed(42)

    cursor.execute("SELECT id FROM annotators")
    annotator_ids = [row['id'] for row in cursor.fetchall()]

    cursor.execute("SELECT id, gold_label, is_gold_standard, image_path FROM images")
    images = cursor.fetchall()

    for image in images:
        # Determine the "true" label
        true_label = image['gold_label'] if image['is_gold_standard'] else categories[image['id'] % len(categories)]

        # Each annotator labels with some noise
        for ann_id in annotator_ids:
            if random.random() < 0.3:  # 30% chance of skipping
                continue

            if ann_id == 5:  # eve_malicious - label flipper
                if random.random() < 0.8:
                    label = random.choice([c for c in categories if c != true_label])
                else:
                    label = true_label
            else:
                if random.random() < 0.85:  # 85% accuracy for honest annotators
                    label = true_label
                else:
                    label = random.choice(categories)

            signature = generate_label_hmac(image['id'], ann_id, label)
            try:
                conn.execute("""
                    INSERT INTO labels (image_id, annotator_id, label, ip_address, hmac_signature)
                    VALUES (?, ?, ?, ?, ?)
                """, (image['id'], ann_id, label, "127.0.0.1", signature))
            except sqlite3.IntegrityError:
                pass

    conn.commit()

    # Run aggregation on all images
    cursor.execute("SELECT id FROM images")
    for image in cursor.fetchall():
        aggregate_labels(conn, image['id'])

    # Update trust scores
    for ann_id in annotator_ids:
        update_trust_score(conn, ann_id)

    conn.commit()
    conn.close()
    print("Demo data seeded successfully.")


