# Main
# ============================================================
def main():
    print("=" * 60)
    print("Crowdsourced Data Labeling System")
    print("=" * 60)

    init_db()
    seed_demo_data()

    # Train model on existing labeled data
    print("\nAttempting initial model training...")
    train_model_on_labeled_data()

    # Print some stats
    conn = get_db()
    cursor = conn.cursor()

    cursor.execute("SELECT COUNT(*) FROM annotators")
    print(f"\nAnnotators: {cursor.fetchone()[0]}")

    cursor.execute("SELECT COUNT(*) FROM images")
    print(f"Images: {cursor.fetchone()[0]}")

    cursor.execute("SELECT COUNT(*) FROM labels WHERE is_valid=1")
    print(f"Valid Labels: {cursor.fetchone()[0]}")

    cursor.execute("SELECT COUNT(*) FROM images WHERE is_finalized=1")
    print(f"Finalized Images: {cursor.fetchone()[0]}")

    cursor.execute("SELECT username, trust_score, total_labels, flagged_count, is_active FROM annotators")
    print("\nAnnotator Trust Scores:")
    for row in cursor.fetchall():
        status = "ACTIVE" if row['is_active'] else "DEACTIVATED"
        print(f"  {row['username']}: trust={row['trust_score']:.3f}, "
              f"labels={row['total_labels']}, flagged={row['flagged_count']}, {status}")

    cursor.execute(
        "SELECT event_type, COUNT(*) as count FROM audit_log GROUP BY event_type ORDER BY count DESC"
    )
    print("\nAudit Log Summary:")
    for row in cursor.fetchall():
        print(f"  {row['event_type']}: {row['count']}")

    conn.close()

    # Start server
    host = '127.0.0.1'
    port = 8080
    server = HTTPServer((host, port), LabelingAPIHandler)
    print(f"\nAPI Server running at http://{host}:{port}")
    print("\nAPI Endpoints:")
    print("  POST /api/register     - Register new annotator")
    print("  POST /api/login        - Login and get API token")
    print("  POST /api/images       - Add image for labeling")
    print("  POST /api/labels       - Submit a label")
    print("  GET  /api/images       - Get images (query: status, limit)")
    print("  GET  /api/labels/status - Get label status (query: image_id)")
    print("  GET  /api/annotators/stats - Get your stats")
    print("  GET  /api/audit        - Get audit logs")
    print("  POST /api/train        - Train model on labeled data")
    print("  POST /api/predict      - Predict label for image")
    print("  GET  /api/health       - Health check")
    print("\nPress Ctrl+C to stop.")

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\nShutting down...")
        server.server_close()


if __name__ == "__main__":
    main()